import { chromium } from "playwright";

interface AgentAction {
  type: "click" | "type" | "navigate" | "extract";
  selector?: string;
  value?: string;
  url?: string;
}

async function autonomousBrowserAgent(task: string) {
  const browser = await chromium.launch({ headless: false });
  const page = await browser.newPage();
  const history: { action: AgentAction; result: string }[] = [];

  for (let i = 0; i < 10; i++) {
    // Get accessibility snapshot (token-efficient alternative to screenshots)
    const snapshot = await page.accessibility.snapshot();
    const pageText = await page.textContent("body");

    // LLM decides next action based on task + history + page state
    const nextAction: AgentAction = await llmDecide({
      task,
      history,
      pageText: pageText?.slice(0, 4000),
      snapshot,
    });

    let result: string;
    switch (nextAction.type) {
      case "navigate":
        await page.goto(nextAction.url!);
        result = `Navigated to ${nextAction.url}`;
        break;
      case "click":
        await page.click(nextAction.selector!);
        result = `Clicked ${nextAction.selector}`;
        break;
      case "type":
        await page.fill(nextAction.selector!, nextAction.value!);
        result = `Typed into ${nextAction.selector}`;
        break;
      case "extract":
        const extracted = await page.textContent(nextAction.selector!);
        result = extracted || "No content found";
        break;
    }

    history.push({ action: nextAction, result });

    // Check if task is complete
    const isComplete = await llmCheckCompletion(task, history);
    if (isComplete) break;
  }

  await browser.close();
  return history;
}

