# Dynamic model selection via middleware
@agent.middleware
async def route_model(ctx, call_next):
    if ctx.complexity_score > 0.8:
        ctx.model = "anthropic:claude-opus-4-6"  # upgrade for hard tasks
    elif ctx.complexity_score < 0.3:
        ctx.model = "anthropic:claude-haiku-3-5"  # downgrade for easy tasks
    return await call_next()

